import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, getDocs, doc, updateDoc, deleteDoc } from 'firebase/firestore';
import { 
  LayoutDashboard, 
  LogOut, 
  CheckCircle, 
  XCircle, 
  Trash2, 
  Clock, 
  LayoutGrid,
  ShieldAlert,
  RefreshCw,
  Database
} from 'lucide-react';

function AdminDashboard({ onLogout }) {
  const [projects, setProjects] = useState([]);
  const [userMap, setUserMap] = useState({});
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false); // 🚨 Tracks the sync process

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const [projectsSnapshot, usersSnapshot] = await Promise.all([
        getDocs(collection(db, "projects")),
        getDocs(collection(db, "users"))
      ]);

      const usersDictionary = {};
      usersSnapshot.docs.forEach(doc => {
        const userData = doc.data();
        if (userData.username) {
          usersDictionary[userData.username] = userData.name;
        }
      });
      setUserMap(usersDictionary);

      const projectsList = projectsSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      
      projectsList.sort((a, b) => (a.status === 'Pending' ? -1 : 1));
      setProjects(projectsList);
      
    } catch (error) {
      console.error("Error fetching dashboard data:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboardData();
  }, []);

  // --- 🛠️ THE NEW DATABASE SYNC TOOL ---
  const handleSyncDatabase = async () => {
    if (!window.confirm("This will scan the database and permanently update all project receipts to match the user's current live name. Proceed?")) return;

    setIsSyncing(true);
    let updateCount = 0;

    try {
      // Loop through every single project currently loaded
      for (const project of projects) {
        let searchUsername = project.authorUsername;

        // Force extract roll no for old projects
        if (!searchUsername || searchUsername === 'unknown') {
          if (project.author && project.author.includes('(')) {
            const match = project.author.match(/\(([^)]+)\)/);
            if (match) searchUsername = match[1].trim();
          }
        }

        // If we found a valid username, and they exist in the user dictionary
        if (searchUsername && userMap[searchUsername]) {
          const correctLiveName = userMap[searchUsername];
          
          // Check if the database has the wrong name
          if (project.authorName !== correctLiveName || project.author !== `${correctLiveName} (${searchUsername})`) {
            
            // 🚨 OFFICIALLY REWRITE THE FIREBASE DATABASE
            const projectRef = doc(db, "projects", project.id);
            await updateDoc(projectRef, {
              authorName: correctLiveName,
              authorUsername: searchUsername,
              author: `${correctLiveName} (${searchUsername})` // Clean up the old display string too
            });
            updateCount++;
          }
        }
      }

      alert(`Database Sync Complete! Successfully fixed and updated ${updateCount} projects in the database.`);
      fetchDashboardData(); // Refresh the screen to show the clean data
    } catch (error) {
      console.error("Sync error:", error);
      alert("Failed to sync database.");
    } finally {
      setIsSyncing(false);
    }
  };

  const updateStatus = async (projectId, newStatus) => {
    try {
      const projectRef = doc(db, "projects", projectId);
      await updateDoc(projectRef, { status: newStatus });
      setProjects(projects.map(p => p.id === projectId ? { ...p, status: newStatus } : p));
    } catch (error) {
      console.error(`Error updating to ${newStatus}:`, error);
    }
  };

  const handleDelete = async (projectId) => {
    if (window.confirm("Are you sure you want to delete this project permanently?")) {
      try {
        await deleteDoc(doc(db, "projects", projectId));
        setProjects(projects.filter(p => p.id !== projectId));
      } catch (error) {
        console.error("Error deleting project:", error);
      }
    }
  };

  const totalProjects = projects.length;
  const pendingProjects = projects.filter(p => p.status === 'Pending').length;
  const approvedProjects = projects.filter(p => p.status === 'Approved').length;

  return (
    <div className="flex h-screen bg-[#0a0a0a] text-gray-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      
      <div className="w-64 bg-[#050505] border-r border-white/10 flex flex-col justify-between relative z-20">
        <div>
          <div className="p-6 border-b border-white/10 flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-xl flex items-center justify-center shadow-lg transform -rotate-3">
              <ShieldAlert className="w-5 h-5 text-white transform rotate-3" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-white tracking-tight">Admin Panel</h1>
              <p className="text-[10px] text-gray-400 uppercase tracking-widest">Command Center</p>
            </div>
          </div>
          
          <nav className="p-4 space-y-2">
            <button className="w-full flex items-center gap-3 bg-white/10 text-white px-4 py-3 rounded-xl font-medium border border-white/5 transition-all shadow-lg">
              <LayoutDashboard className="w-5 h-5 text-indigo-400" /> Dashboard
            </button>
            
            {/* 🚨 THE NEW DATABASE SYNC BUTTON */}
            <button 
              onClick={handleSyncDatabase}
              disabled={isSyncing}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium border transition-all shadow-lg ${
                isSyncing 
                  ? 'bg-indigo-500/20 text-indigo-300 border-indigo-500/30 cursor-wait' 
                  : 'bg-black/40 text-gray-300 border-white/5 hover:bg-white/5 hover:text-white'
              }`}
            >
              {isSyncing ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Database className="w-5 h-5 text-purple-400" />} 
              {isSyncing ? 'Syncing...' : 'Sync Database'}
            </button>
          </nav>
        </div>

        <div className="p-4 border-t border-white/10">
          <button 
            onClick={onLogout}
            className="w-full flex items-center gap-3 text-red-400 hover:bg-red-500/10 hover:text-red-300 px-4 py-3 rounded-xl font-medium transition-all"
          >
            <LogOut className="w-5 h-5" /> Secure Logout
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-8 relative custom-scrollbar">
        <div className="absolute top-0 left-1/4 w-[600px] h-[400px] bg-indigo-600/10 blur-[150px] rounded-full pointer-events-none"></div>

        <div className="max-w-6xl mx-auto relative z-10">
          <h2 className="text-3xl font-extrabold text-white mb-8">Project Overview</h2>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
            <div className="bg-white/5 border border-white/10 p-6 rounded-2xl backdrop-blur-md shadow-xl flex flex-col relative overflow-hidden group">
              <div className="absolute right-0 top-0 w-24 h-24 bg-blue-500/10 rounded-bl-full transition-transform group-hover:scale-110"></div>
              <span className="text-gray-400 text-sm font-bold uppercase tracking-wider mb-2 z-10">Total Projects</span>
              <span className="text-4xl font-extrabold text-white z-10">{totalProjects}</span>
            </div>
            
            <div className="bg-white/5 border border-white/10 p-6 rounded-2xl backdrop-blur-md shadow-xl flex flex-col relative overflow-hidden group">
              <div className="absolute right-0 top-0 w-24 h-24 bg-yellow-500/10 rounded-bl-full transition-transform group-hover:scale-110"></div>
              <span className="text-gray-400 text-sm font-bold uppercase tracking-wider mb-2 z-10">Pending Review</span>
              <span className="text-4xl font-extrabold text-yellow-400 z-10">{pendingProjects}</span>
            </div>

            <div className="bg-white/5 border border-white/10 p-6 rounded-2xl backdrop-blur-md shadow-xl flex flex-col relative overflow-hidden group">
              <div className="absolute right-0 top-0 w-24 h-24 bg-green-500/10 rounded-bl-full transition-transform group-hover:scale-110"></div>
              <span className="text-gray-400 text-sm font-bold uppercase tracking-wider mb-2 z-10">Live Approved</span>
              <span className="text-4xl font-extrabold text-green-400 z-10">{approvedProjects}</span>
            </div>
          </div>

          <div className="bg-white/5 border border-white/10 rounded-[2rem] backdrop-blur-md shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-white/10">
              <h3 className="text-lg font-bold text-white flex items-center gap-2">
                <LayoutGrid className="w-5 h-5 text-indigo-400" /> Submissions Ledger
              </h3>
            </div>
            
            <div className="overflow-x-auto">
              {loading ? (
                <div className="p-10 text-center text-gray-500 animate-pulse">Loading database records...</div>
              ) : projects.length === 0 ? (
                <div className="p-10 text-center text-gray-500">No projects found in the repository.</div>
              ) : (
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-black/20 text-xs text-gray-400 uppercase tracking-widest">
                      <th className="p-5 font-semibold border-b border-white/5">Project Name</th>
                      <th className="p-5 font-semibold border-b border-white/5">Developer</th>
                      <th className="p-5 font-semibold border-b border-white/5">Category</th>
                      <th className="p-5 font-semibold border-b border-white/5">Status</th>
                      <th className="p-5 font-semibold border-b border-white/5 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/5">
                    {projects.map((project) => {
                      
                      let searchUsername = project.authorUsername;

                      if (project.author && project.author.includes('(')) {
                        const match = project.author.match(/\(([^)]+)\)/);
                        if (match) {
                          searchUsername = match[1].trim();
                        }
                      }

                      const liveName = searchUsername ? userMap[searchUsername] : null;
                      const isValidUsername = searchUsername && searchUsername !== 'unknown' && searchUsername !== 'undefined' && searchUsername !== 'null';
                      const displayUsername = isValidUsername ? searchUsername : 'N/A';
                      
                      // Even before syncing, show them the correct visual
                      const authorDisplay = liveName 
                        ? `${liveName} (${displayUsername})` 
                        : (project.author || `${project.authorName || 'Unknown'} (${displayUsername})`);
                      
                      return (
                        <tr key={project.id} className="hover:bg-white/5 transition-colors group">
                          
                          <td className="p-5">
                            <p className="font-bold text-white group-hover:text-indigo-300 transition-colors">{project.title}</p>
                            <p className="text-xs text-gray-500 font-mono mt-0.5">ID: {project.id.slice(0, 8)}</p>
                          </td>
                          
                          <td className="p-5 text-sm text-gray-300">
                            {authorDisplay}
                          </td>
                          
                          <td className="p-5">
                            <span className="bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wider">
                              {project.category || 'App'}
                            </span>
                          </td>
                          
                          <td className="p-5">
                            {project.status === 'Approved' && (
                              <span className="inline-flex items-center gap-1.5 bg-green-500/10 border border-green-500/20 text-green-400 text-xs px-3 py-1.5 rounded-full font-semibold">
                                <CheckCircle className="w-3.5 h-3.5" /> Approved
                              </span>
                            )}
                            {project.status === 'Pending' && (
                              <span className="inline-flex items-center gap-1.5 bg-yellow-500/10 border border-yellow-500/20 text-yellow-400 text-xs px-3 py-1.5 rounded-full font-semibold">
                                <Clock className="w-3.5 h-3.5" /> Pending
                              </span>
                            )}
                            {project.status === 'Rejected' && (
                              <span className="inline-flex items-center gap-1.5 bg-red-500/10 border border-red-500/20 text-red-400 text-xs px-3 py-1.5 rounded-full font-semibold">
                                <XCircle className="w-3.5 h-3.5" /> Rejected
                              </span>
                            )}
                          </td>
                          
                          <td className="p-5">
                            <div className="flex justify-end gap-2">
                              {project.status !== 'Approved' && (
                                <button 
                                  onClick={() => updateStatus(project.id, 'Approved')}
                                  title="Approve"
                                  className="p-2 bg-green-500/10 text-green-400 hover:bg-green-500 hover:text-white rounded-lg transition-all border border-green-500/20"
                                >
                                  <CheckCircle className="w-4 h-4" />
                                </button>
                              )}
                              
                              {project.status !== 'Rejected' && (
                                <button 
                                  onClick={() => updateStatus(project.id, 'Rejected')}
                                  title="Reject"
                                  className="p-2 bg-yellow-500/10 text-yellow-400 hover:bg-yellow-500 hover:text-white rounded-lg transition-all border border-yellow-500/20"
                                >
                                  <XCircle className="w-4 h-4" />
                                </button>
                              )}

                              <button 
                                onClick={() => handleDelete(project.id)}
                                title="Delete Permanently"
                                className="p-2 bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white rounded-lg transition-all border border-red-500/20"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </div>
                          </td>

                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              )}
            </div>
          </div>
          
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
